61	// ============================================================
62	// Constants
63	// ============================================================
64	
65	/** Early detection 預設配置 */
66	export const EARLY_DETECTION_RETRY: RetryConfig = {
67	  maxRetries: 10,
68	  retryDelay: 100,
69	  initialDelay: 50,
70	};
71	
72	/** Fallback detection 預設配置 */
73	export const FALLBACK_DETECTION_RETRY: RetryConfig = {
74	  maxRetries: 5,
75	  retryDelay: 100,
76	  initialDelay: 100,
77	};
78	
79	/**
80	 * spawnRegistry 反查 retry 參數（Phase 2 nested parent lookup）。
81	 * 蓋住 parent JSONL line 在 nested 檔案出現後才被解析的 race window。
82	 * 4 × 50 = 最壞 150ms（不含最後一輪的 sleep）— Claude Code 實測時序為前提。
83	 */
84	export const PARENT_LOOKUP_MAX_ATTEMPTS = 4;
85	export const PARENT_LOOKUP_DELAY_MS = 50;
86	
87	/**
88	 * subagents/ 與其父目錄都不存在時的初始 retry 間隔（base）。
89	 * agent-tail 在首個 subagent 出現前啟動是常態，必須持續輪詢直到目錄被建立。
90	 * 指數退避：1s, 2s, 4s, 8s, 16s, 30s, 30s...（cap）
91	 */
92	export const SUBAGENTS_DIR_RETRY_DELAY_MS = 1000;
93	export const SUBAGENTS_DIR_RETRY_MAX_DELAY_MS = 30000;
94	
95	/** 建立 subagent 檔案路徑 */
96	export function buildSubagentPath(
97	  subagentsDir: string,
98	  agentId: string
99	): string {
100	  return join(subagentsDir, `agent-${agentId}.jsonl`);
101	}
102	
103	/** 建立 subagent meta.json 檔案路徑 */
104	export function buildSubagentMetaPath(
105	  subagentsDir: string,
106	  agentId: string
107	): string {
108	  return join(subagentsDir, `agent-${agentId}.meta.json`);
109	}
110	
111	/**
112	 * Subagent meta.json 結構
113	 * Claude Code 在 spawn subagent 時會寫入此檔（包含 nested subagent）
114	 */
115	interface SubagentMeta {
116	  agentType?: string;
117	  description?: string;
118	  toolUseId?: string;
119	  name?: string;
120	}
121	
122	/**
123	 * 嘗試讀取 subagent 的 meta.json（含 retry）
124	 * meta.json 可能稍晚於 .jsonl 寫入，需要短暫重試
125	 *
126	 * @param subagentsDir subagents 目錄
127	 * @param agentId agent 識別碼
128	 * @param retries 重試次數（預設 3，最壞 150ms）
129	 * @param retryDelayMs 每次重試間隔（預設 50ms）
130	 */
131	export async function readSubagentMeta(
132	  subagentsDir: string,
133	  agentId: string,
134	  retries = 3,
135	  retryDelayMs = 50
136	): Promise<SubagentMeta | null> {
137	  const metaPath = buildSubagentMetaPath(subagentsDir, agentId);
138	  for (let attempt = 0; attempt <= retries; attempt++) {
139	    try {
140	      // 直讀 text()，缺檔走 catch 而非預先 exists()（少一次 syscall + 去 TOCTOU）
141	      const text = await Bun.file(metaPath).text();
142	      const parsed = JSON.parse(text) as SubagentMeta;
143	      return parsed;
144	    } catch {
145	      // 讀取或解析失敗，視為缺漏 → 重試
146	    }
147	    if (attempt < retries) {
148	      await new Promise((resolve) => setTimeout(resolve, retryDelayMs));
149	    }
150	  }
151	  return null;
152	}
153	
154	/** 從 session 檔案路徑推導 subagents 目錄 */
155	export function getSubagentsDir(sessionFilePath: string): string {
156	  const projectDir = dirname(sessionFilePath);
157	  const sessionId = basename(sessionFilePath, '.jsonl');
158	  return join(projectDir, sessionId, 'subagents');
159	}
