161	// ============================================================
162	// Utility Functions
163	// ============================================================
164	
165	/**
166	 * 驗證 agentId 格式
167	 * 支援 7-40 位十六進制字符（涵蓋短 hash 到完整 SHA-1）
168	 * 同時防止路徑穿越攻擊
169	 */
170	export function isValidAgentId(agentId: string): boolean {
171	  return /^[0-9a-f]{7,40}$/i.test(agentId);
172	}
173	
174	/**
175	 * 從一個 JSONL 檔案內所有 assistant message 的 tool_use 區段中，
176	 * 收集 subagent spawn tool（Task / Agent — Claude Code 版本演進過的名稱）的
177	 * (toolUseId, source) 配對。
178	 * source 表示「誰呼叫了這次 tool_use」（主 session 或某個 subagent）。
179	 *
180	 * 用於 cold attach 時預跑：把所有歷史 spawn 關係蒐齊，再對應到每個既存
181	 * subagent 的 meta.toolUseId，補出 [child◂parent] label。
182	 */
183	async function collectAgentSpawnsFromJsonl(
184	  filePath: string,
185	  source: string
186	): Promise<Array<[string, string]>> {
187	  const pairs: Array<[string, string]> = [];
188	  try {
189	    const text = await Bun.file(filePath).text();
190	    for (const line of text.split('\n')) {
191	      // 前置子字串檢查避免每行都 JSON.parse（熱路徑優化）
192	      // 涵蓋 Task 與 Agent 兩種 spawn tool 名稱（與 isSubagentTool 一致）
193	      if (!SPAWN_TOOL_PREFILTER.some((pat) => line.includes(pat))) continue;
194	      try {
195	        const data = JSON.parse(line) as {
196	          type?: string;
197	          message?: {
198	            content?: Array<{ type?: string; name?: string; id?: string }>;
199	          };
200	        };
201	        if (data.type !== 'assistant') continue;
202	        const content = data.message?.content;
203	        if (!Array.isArray(content)) continue;
204	        for (const c of content) {
205	          if (
206	            c &&
207	            c.type === 'tool_use' &&
208	            typeof c.name === 'string' &&
209	            isSubagentTool(c.name) &&
210	            typeof c.id === 'string'
211	          ) {
212	            pairs.push([c.id, source]);
213	          }
214	        }
215	      } catch {
216	        /* skip non-JSON */
217	      }
218	    }
219	  } catch {
220	    /* skip missing/unreadable file */
221	  }
222	  return pairs;
223	}
