225	/**
226	 * Cold attach 時對所有既存 subagent 預解析 parent 關係。
227	 *
228	 * 流程：
229	 * 1. 平行讀主 session 與每個 subagent JSONL，收集所有 Agent tool_use 的
230	 *    (toolUseId → source) 配對（source = MAIN_SOURCE 或某 agentId）。
231	 * 2. 平行讀每個 subagent 的 meta.json，用 meta.toolUseId 反查上表。
232	 *
233	 * @param subagentsDir subagents 目錄
234	 * @param mainSessionPath 主 session JSONL 路徑
235	 * @param agentIds 既存 subagent 的 id 集合
236	 * @returns Map<agentId, parentAgentId | undefined>
237	 *   - undefined：parent 是主 session（label 維持 `[child]`）或查不到
238	 *   - 字串：nested parent 的 agentId（label 為 `[child◂parent]`）
239	 */
240	export async function resolveExistingParents(
241	  subagentsDir: string,
242	  mainSessionPath: string,
243	  agentIds: Iterable<string>
244	): Promise<Map<string, string | undefined>> {
245	  const ids = [...agentIds];
246	  const parentMap = new Map<string, string | undefined>();
247	  if (ids.length === 0) return parentMap;
248	
249	  // 1. 平行收集所有 Agent tool_use 的 (toolUseId → source)
250	  const collectionTasks: Array<Promise<Array<[string, string]>>> = [
251	    collectAgentSpawnsFromJsonl(mainSessionPath, MAIN_SOURCE),
252	    ...ids.map((id) =>
253	      collectAgentSpawnsFromJsonl(buildSubagentPath(subagentsDir, id), id)
254	    ),
255	  ];
256	  const collected = await Promise.all(collectionTasks);
257	  const spawnSources = new Map(collected.flat());
258	
259	  // 2. 平行讀每個 subagent 的 meta.json（cold attach 檔案穩定，retry=0）
260	  const metaResults = await Promise.all(
261	    ids.map(async (id) => ({
262	      id,
263	      meta: await readSubagentMeta(subagentsDir, id, 0, 0),
264	    }))
265	  );
266	
267	  // 3. 反查
268	  for (const { id, meta } of metaResults) {
269	    const source = meta?.toolUseId
270	      ? spawnSources.get(meta.toolUseId)
271	      : undefined;
272	    parentMap.set(id, source && source !== MAIN_SOURCE ? source : undefined);
273	  }
274	  return parentMap;
275	}
