287	  private _startSubagentDirWatch(): void {
288	    try {
289	      this.subagentDirWatcher = watch(
290	        this.config.workflow.transcriptDir,
291	        (_eventType, filename) => {
292	          if (this.stopped || !filename) return;
293	          const agentId = parseWorkflowAgentFilename(filename);
294	          if (!agentId || !isValidWorkflowAgentId(agentId)) return;
295	          const transcriptPath = join(
296	            this.config.workflow.transcriptDir,
297	            filename
298	          );
299	          void this.attachAgent(agentId, transcriptPath);
300	        }
301	      );
302	      this.subagentDirWatcher.on('error', (err) =>
303	        this.config.outputHandler.debug(
304	          `[wf:${this.config.workflow.runId}] subagent dir watch error: ${err}`
305	        )
306	      );
307	    } catch (err) {
308	      this.config.outputHandler.debug(
309	        `[wf:${this.config.workflow.runId}] subagent dir watch failed: ${err}`
310	      );
311	    }
312	  }
