    const detector = new WorkflowDetector({
      sessionUuid: 'uuid',
      sessionDir: join(tempDir, 'no-such-session'),
      onNewWorkflow: () => {},
      outputHandler: handler,
    });
    let threw = false;
    try {
      await detector.start();
    } catch {
      threw = true;
    }
